async (page) => {
  await page.evaluate(() => window.game.player.setAttackStyle(0)); // 0 = Hack
  return 'Set attack style to Hack';
}

async (page) => {
  // Click northeast to walk toward the Forester at x=216, y=114
  // Player is at x=138, y=173 - need to go NE
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 900, y: 100 });
  await page.waitForTimeout(4000);
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    if (!gs) return 'No state';
    return JSON.stringify({ player_position: gs.player_position, nearby_entities: (gs.nearby_entities || []).slice(0, 8).map(e => ({ name: e.name, type: e.type, x: e.x, y: e.y, distance: e.distance, click_x: e.click_x, click_y: e.click_y, on_screen: e.on_screen, quest_npc: e.quest_npc })) });
  });
  return state;
}

